<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Enums\PerformanceEvaluationStatus; use App\Modules\Hr\Performance\Models\HrPerformanceEvaluation; use Illuminate\Support\Facades\DB;
class SubmitPerformanceEvaluationAction { public function __construct(private HrAuditService $audit){} public function execute(HrPerformanceEvaluation $evaluation,array $answers):HrPerformanceEvaluation{abort_unless($evaluation->legal_entity_id===app(TenantContext::class)->getId(),404);$evaluation->loadMissing(['reviewer','template']);abort_unless($evaluation->reviewer?->user_id===auth()->id()||auth()->user()?->hasHrPermission('hr.performance.evaluate'),403);return DB::transaction(function()use($evaluation,$answers){$row=HrPerformanceEvaluation::withoutGlobalScope('tenant')->whereKey($evaluation->id)->lockForUpdate()->firstOrFail();abort_unless($row->status===PerformanceEvaluationStatus::Draft,422,'Gönderilmiş değerlendirme değiştirilemez.');$row->load('template');$score=0;foreach($row->template->sections as $section)foreach($section['questions'] as $question){$id=(string)$question['id'];$value=(float)($answers[$id]??0);abort_if($value<1||$value>5,422,"{$id} için 1-5 arası puan zorunludur.");$score+=($value/5)*(float)$question['weight'];}$row->update(['answers'=>$answers,'overall_score'=>round($score,2),'status'=>PerformanceEvaluationStatus::Submitted,'submitted_at'=>now()]);$this->audit->log('performance_evaluation_submitted',$row,null,['overall_score'=>round($score,2),'reviewer_type'=>$row->reviewer_type->value]);return $row->fresh();});} }
